import Fastify from "fastify";
import type { FastifyInstance, FastifyRequest, FastifyReply } from "fastify";
import { WebSocketServer, WebSocket } from "ws";
import type { IncomingMessage } from "node:http";
import type { Duplex } from "node:stream";

import type { Command, CommandResult } from "../shared/types.js";
import { ErrorCategory } from "../shared/types.js";
import { RexError } from "../shared/errors.js";
import type { Logger } from "../shared/logger.js";
import type { Config } from "../shared/config.js";
import { CommandQueue } from "./command-queue.js";
import { ConnectionManager } from "./connection.js";
import type { ConnectPayload } from "./connection.js";
import { HeartbeatMonitor } from "./heartbeat.js";
import { CommentWatcher } from "./comment-watcher.js";
import { MemoryServiceClient } from "../memory/client.js";
import { loadMemoryConfig } from "../memory/config.js";
import type { MemoryConfig, ChatHistoryEntry, ChatSession, MemoryContext } from "../memory/types.js";

// ─── Types ──────────────────────────────────────────────────────────────────

/** WebSocket message envelope. */
interface WsMessage {
  type: "command" | "result" | "ack" | "ping" | "pong";
  id?: string;
  payload?: Record<string, unknown>;
  timestamp: number;
}

/** Adaptive polling state. */
interface PollingState {
  lastCommandTime: number;
}

// ─── Relay Server ───────────────────────────────────────────────────────────

const VERSION = "0.3.0";

export class RelayServer {
  private readonly config: Config;
  private readonly logger: Logger;
  readonly queue: CommandQueue;
  readonly connection: ConnectionManager;
  readonly heartbeat: HeartbeatMonitor;

  private fastify: FastifyInstance | null = null;
  private wss: WebSocketServer | null = null;
  private wsClient: WebSocket | null = null;
  private startTime: number = 0;
  private pollingState: PollingState = { lastCommandTime: 0 };
  private _boundPort: number = 0;

  /** The port the relay actually bound to (may differ from config if port was in use). */
  get boundPort(): number {
    return this._boundPort;
  }

  // Chat message queue (plugin → MCP server) — bounded FIFO queue
  private readonly CHAT_INBOX_MAX = 50;
  private chatInbox: Array<{ id: string; message: string; selection: unknown[]; timestamp: number }> = [];
  private chatWaiters: Array<{ resolve: (msg: { id: string; message: string; selection: unknown[]; timestamp: number }) => void; timer: ReturnType<typeof setTimeout> }> = [];

  // Chat response queue (MCP server → plugin) — bounded
  private readonly CHAT_OUTBOX_MAX = 50;
  private chatOutbox: Array<{ id: string; message: string; timestamp: number; isError?: boolean; _isChunk?: boolean; _done?: boolean }> = [];

  // Comment watcher for @rex mentions
  private readonly commentWatcher: CommentWatcher;

  // Memory system
  private readonly memoryConfig: MemoryConfig;
  private _memoryStore: MemoryServiceClient | null = null;

  // Stream accumulator for persisting complete streaming responses
  private streamAccumulator: Map<string, string> = new Map();

  // Active chat session for session-based conversations
  private _activeChatSession: ChatSession | null = null;

  /** The active chat session ID (null if no session selected). */
  get activeChatSessionId(): string | null {
    return this._activeChatSession?.sessionId ?? null;
  }

  /** The active chat session name. */
  get activeChatSessionName(): string | null {
    return this._activeChatSession?.name ?? null;
  }

  /** Update the active session's name (called when Claude names a session). */
  updateChatSessionName(name: string): void {
    if (!this._activeChatSession) return;
    this._activeChatSession.name = name;
    this.logger.info("Chat session renamed", { sessionId: this._activeChatSession.sessionId, name });

    // Persist immediately
    if (this._memoryStore && this.connection.session) {
      const pluginSession = this.connection.session;
      const ctx: MemoryContext = {
        fileKey: pluginSession.fileKey,
        fileName: pluginSession.fileName,
        userId: pluginSession.user?.id,
        userName: pluginSession.user?.name,
      };
      this._memoryStore.updateSession(this._activeChatSession, ctx).catch((err) => {
        this.logger.warn("Failed to persist session name", {
          error: err instanceof Error ? err.message : String(err),
        });
      });
    }
  }

  /** Access the memory store (null if disabled/not connected). */
  get memoryStore(): MemoryServiceClient | null {
    return this._memoryStore;
  }


  constructor(config: Config, logger: Logger) {
    this.config = config;
    this.logger = logger.child({ component: "relay-server" });
    this.queue = new CommandQueue(config.commands, this.logger);
    this.connection = new ConnectionManager(this.logger);
    this.heartbeat = new HeartbeatMonitor(
      this.connection,
      config.websocket,
      this.logger,
    );

    // Create comment watcher — injects @rex mentions into chat inbox
    this.commentWatcher = new CommentWatcher(config, this.logger, (msg) => {
      this.enqueueChatMessage(msg);
    });

    // Load memory configuration
    this.memoryConfig = loadMemoryConfig();

    this.wireQueueEvents();
  }

  /** Wire command queue events to heartbeat metrics. */
  private wireQueueEvents(): void {
    this.queue.on("enqueued", () => {
      this.heartbeat.recordCommandTotal();
    });
    this.queue.on("completed", (_id: string, result: CommandResult) => {
      if (result.status === "success") {
        this.heartbeat.recordCommandSuccess(result.duration);
      } else {
        this.heartbeat.recordCommandFailed();
      }
    });
    this.queue.on("timeout", () => {
      this.heartbeat.recordCommandTimeout();
    });
    this.queue.on("retry", () => {
      this.heartbeat.recordCommandRetried();
    });
    this.queue.on("failed", () => {
      this.heartbeat.recordCommandFailed();
    });
  }

  /**
   * Start the relay server.
   * Binds HTTP + WebSocket to the configured host:port.
   */
  async start(): Promise<void> {
    this.startTime = Date.now();

    const { host } = this.config.relay;

    // Create Fastify instance with a custom HTTP server so we can intercept
    // upgrade requests for WebSocket before Fastify processes them.
    this.fastify = Fastify({
      logger: false, // We use our own logger
      bodyLimit: 10 * 1024 * 1024, // 10MB — screenshots and deep node trees can be large
    });

    // CORS: Figma plugin UI iframe has origin "null", must allow cross-origin
    this.fastify.addHook("onRequest", async (request, reply) => {
      reply.header("Access-Control-Allow-Origin", "*");
      reply.header("Access-Control-Allow-Methods", "GET, POST, OPTIONS");
      reply.header("Access-Control-Allow-Headers", "Content-Type, X-Plugin-Id, X-Plugin-File, X-Plugin-Page, X-Session-Id, X-Auth-Token");

      if (request.method === "OPTIONS") {
        reply.status(204).send();
      }
    });

    this.registerRoutes(this.fastify);

    // Bind to the first available port in the range
    const port = await this.bindToAvailablePort(host);

    // Set up WebSocket server on the same HTTP server
    if (this.config.websocket.enabled) {
      const httpServer = this.fastify.server;
      this.wss = new WebSocketServer({ noServer: true });

      httpServer.on("upgrade", (request: IncomingMessage, socket: Duplex, head: Buffer) => {
        this.handleUpgrade(request, socket, head);
      });

      this.logger.info("WebSocket server ready on upgrade path /ws");
    }

    // Initialize memory (optional, non-blocking)
    if (this.memoryConfig.enabled) {
      this._memoryStore = new MemoryServiceClient(
        this.memoryConfig.serviceUrl,
        this.logger,
      );
      this._memoryStore.connect().catch((err) => {
        this.logger.warn("Memory service connection failed (non-fatal)", {
          error: err instanceof Error ? err.message : String(err),
        });
      });
    }

    this.logger.info("Relay server started", { host, port });
  }

  /**
   * Try each port in the configured range until one binds successfully.
   * If port is 0 (test mode), let the OS assign a random port.
   * Returns the port that was bound.
   */
  private async bindToAvailablePort(host: string): Promise<number> {
    const { port: preferredPort, portRangeStart, portRangeEnd } = this.config.relay;

    // Port 0 = OS-assigned random port (used in tests)
    if (preferredPort === 0) {
      await this.fastify!.listen({ host, port: 0 });
      const addr = this.fastify!.server.address();
      this._boundPort = typeof addr === "object" && addr ? addr.port : 0;
      return this._boundPort;
    }

    const start = portRangeStart ?? preferredPort;
    const end = portRangeEnd ?? preferredPort;

    for (let port = start; port <= end; port++) {
      try {
        await this.fastify!.listen({ host, port });
        this._boundPort = port;
        return port;
      } catch (err: unknown) {
        const code = (err as NodeJS.ErrnoException).code;
        if (code === "EADDRINUSE") {
          this.logger.debug("Port in use, trying next", { port });
          continue;
        }
        throw err;
      }
    }

    throw new RexError({
      category: ErrorCategory.INTERNAL_ERROR,
      message: `All Rex relay ports (${start}–${end}) are in use`,
      retryable: false,
      suggestion: "Close an existing Rex session to free a port.",
    });
  }

  /**
   * Stop the relay server gracefully.
   */
  async stop(): Promise<void> {
    this.logger.info("Stopping relay server");

    // Close WebSocket
    if (this.wsClient) {
      this.wsClient.close(1001, "Server shutting down");
      this.wsClient = null;
    }
    if (this.wss) {
      this.wss.close();
      this.wss = null;
    }

    // Clean up chat waiters
    for (const waiter of this.chatWaiters) {
      clearTimeout(waiter.timer);
      waiter.resolve(null as unknown as { id: string; message: string; selection: unknown[]; timestamp: number });
    }
    this.chatWaiters = [];
    this.chatInbox = [];
    this.chatOutbox = [];
    this.streamAccumulator.clear();
    this._activeChatSession = null;

    // Clean up components
    this.commentWatcher.stop();
    this.heartbeat.destroy();
    this.queue.destroy();

    // Disconnect memory store
    if (this._memoryStore) {
      await this._memoryStore.disconnect();
      this._memoryStore = null;
    }

    // Close Fastify
    if (this.fastify) {
      await this.fastify.close();
      this.fastify = null;
    }

    this.logger.info("Relay server stopped");
  }

  // ─── Activity Signal ──────────────────────────────────────────────────

  /** Track active tool count for nested/parallel tool calls. */
  private activeToolCount = 0;

  /**
   * Signal that a tool is starting or finishing.
   * Pushes a lightweight notification to the plugin so the forging
   * animation shows while Claude is working — before commands even arrive.
   */
  signalActivity(active: boolean): void {
    if (active) {
      this.activeToolCount++;
    } else {
      this.activeToolCount = Math.max(0, this.activeToolCount - 1);
    }

    const shouldForge = this.activeToolCount > 0;

    // Push via WebSocket if connected (instant delivery)
    if (this.wsClient?.readyState === WebSocket.OPEN) {
      const msg: WsMessage = {
        type: "command",
        id: "activity-signal",
        payload: { activity: shouldForge } as unknown as Record<string, unknown>,
        timestamp: Date.now(),
      };
      this.wsClient.send(JSON.stringify(msg));
    }

    // Also store for HTTP polling pickup
    this._activityState = shouldForge;
  }

  /** Current activity state for HTTP polling responses. */
  private _activityState = false;

  /** Whether any tools are currently active (for polling responses). */
  get isActive(): boolean {
    return this._activityState;
  }

  // Chat is always available when server is running — messages queue in the bounded inbox.
  // The old chatListening state machine has been removed. Plugin always shows chat as available.

  // ─── Chat Infrastructure ──────────────────────────────────────────────

  /**
   * Called by the plugin to send a chat message.
   * Queue-first: message always enters the bounded FIFO inbox.
   * If a waiter exists, it consumes from the queue immediately.
   */
  enqueueChatMessage(msg: { id: string; message: string; selection: unknown[]; timestamp: number }): void {
    // Persist to remote history (fire-and-forget)
    this.persistChatMessage({
      id: msg.id,
      role: "user",
      message: msg.message,
      timestamp: msg.timestamp,
      fileKey: this.connection.session?.fileKey ?? "",
      selection: msg.selection as Array<{ id: string; name: string; type: string }>,
    });

    // If a waiter exists, deliver directly — skip the queue
    const waiter = this.chatWaiters.shift();
    if (waiter) {
      clearTimeout(waiter.timer);
      waiter.resolve(msg);
      return;
    }

    // No waiter — queue the message
    if (this.chatInbox.length >= this.CHAT_INBOX_MAX) {
      const dropped = this.chatInbox.shift();
      this.logger.warn("Chat inbox overflow — dropped oldest message", { droppedId: dropped?.id });
    }
    this.chatInbox.push(msg);
  }

  /** Number of pending chat messages in the inbox. */
  get pendingChatCount(): number {
    return this.chatInbox.length;
  }

  /** Persist a chat message to the remote memory service (fire-and-forget). */
  private persistChatMessage(entry: ChatHistoryEntry): void {
    if (!this._memoryStore || !this.connection.session) return;
    const pluginSession = this.connection.session;
    const ctx: MemoryContext = {
      fileKey: pluginSession.fileKey,
      fileName: pluginSession.fileName,
      userId: pluginSession.user?.id,
      userName: pluginSession.user?.name,
    };

    // Tag with session ID if an active chat session exists
    const chatSession = this._activeChatSession;
    if (chatSession) {
      entry.sessionId = chatSession.sessionId;
    }

    // Use session-specific tags if we have an active session
    const tags = chatSession
      ? ["chat-message", chatSession.sessionId]
      : ["chat-history", entry.role];

    this._memoryStore.remember({
      scope: "file",
      category: "context",
      content: JSON.stringify(entry.message.length > 2000 ? { ...entry, message: entry.message.slice(0, 2000) } : entry),
      tags,
      source: "explicit",
      context: ctx,
    }).catch((err) => {
      this.logger.warn("Failed to persist chat message", {
        id: entry.id,
        error: err instanceof Error ? err.message : String(err),
      });
    });

    // Update session metadata in memory (summary, messageCount, lastMessageAt)
    if (chatSession) {
      chatSession.messageCount++;
      chatSession.lastMessageAt = entry.timestamp;
      chatSession.summary = entry.message.slice(0, 100);

      // Persist session metadata on every message so summaries are always up-to-date
      if (this._memoryStore) {
        this._memoryStore.updateSession(chatSession, ctx).catch((err) => {
          this.logger.warn("Failed to update chat session", {
            sessionId: chatSession.sessionId,
            error: err instanceof Error ? err.message : String(err),
          });
        });
      }
    }
  }

  /**
   * Called by the MCP tool `wait_for_chat` to consume a message from the queue.
   * Returns immediately if messages are queued, otherwise waits up to timeoutMs.
   */
  waitForChatMessage(timeoutMs: number): Promise<{ id: string; message: string; selection: unknown[]; timestamp: number } | null> {
    // Check inbox first — return immediately if messages are queued
    const queued = this.chatInbox.shift();
    if (queued) {
      return Promise.resolve(queued);
    }

    // No messages queued — long-poll until one arrives or timeout
    return new Promise((resolve) => {
      const timer = setTimeout(() => {
        // Remove this waiter
        const idx = this.chatWaiters.findIndex(w => w.resolve === resolve);
        if (idx >= 0) this.chatWaiters.splice(idx, 1);
        resolve(null);
      }, timeoutMs);

      this.chatWaiters.push({ resolve, timer });
    });
  }

  /**
   * Called by the MCP tool `send_chat_response` to push a response back to the plugin.
   * Delivers via WebSocket if connected, otherwise queues for HTTP polling.
   */
  sendChatResponse(response: { id: string; message: string; timestamp: number; isError?: boolean }): void {
    // Persist non-error responses to remote history (fire-and-forget)
    if (!response.isError) {
      this.persistChatMessage({
        id: response.id,
        role: "assistant",
        message: response.message,
        timestamp: response.timestamp,
        fileKey: this.connection.session?.fileKey ?? "",
      });
    }

    // ALWAYS queue for HTTP polling — this is the reliable baseline.
    // WebSocket is an optional fast path but can silently fail.
    if (this.chatOutbox.length >= this.CHAT_OUTBOX_MAX) {
      const dropped = this.chatOutbox.shift();
      this.logger.warn("Chat outbox overflow — dropped oldest response", { droppedId: dropped?.id });
    }
    this.chatOutbox.push(response);
    this.logger.debug("Chat response queued for delivery", { id: response.id, outboxSize: this.chatOutbox.length });

    // Also push via WebSocket for instant delivery (best-effort)
    if (this.wsClient?.readyState === WebSocket.OPEN) {
      try {
        const msg: WsMessage = {
          type: "command",
          id: "chat-response",
          payload: { chatResponse: response } as unknown as Record<string, unknown>,
          timestamp: Date.now(),
        };
        this.wsClient.send(JSON.stringify(msg));
        this.logger.debug("Chat response also sent via WebSocket", { id: response.id });
      } catch {
        this.logger.warn("Chat response WS send failed — HTTP polling will deliver", { id: response.id });
      }
    } else {
      this.logger.debug("Chat response WS unavailable — HTTP polling only", { id: response.id });
    }
  }

  /**
   * Called by the MCP tool `send_chat_chunk` to push a streaming chunk to the plugin.
   * Delivers via WebSocket if connected, otherwise queues for HTTP polling.
   */
  sendChatChunk(chunk: { id: string; delta: string; done: boolean; timestamp: number }): void {
    // Accumulate streaming deltas for history persistence
    const acc = this.streamAccumulator.get(chunk.id) ?? "";
    this.streamAccumulator.set(chunk.id, acc + chunk.delta);
    if (chunk.done) {
      const fullText = this.streamAccumulator.get(chunk.id) ?? "";
      this.streamAccumulator.delete(chunk.id);
      this.persistChatMessage({
        id: chunk.id,
        role: "assistant",
        message: fullText,
        timestamp: chunk.timestamp,
        fileKey: this.connection.session?.fileKey ?? "",
      });
    }

    const wsOpen = this.wsClient?.readyState === WebSocket.OPEN;

    // Prefer WebSocket for chunks (real-time delivery). Fall back to HTTP
    // polling only if WS is unavailable. Sending via both transports would
    // cause duplicate deltas in the streaming UI.
    if (wsOpen) {
      try {
        const msg: WsMessage = {
          type: "command",
          id: "chat-chunk",
          payload: { chatChunk: chunk } as unknown as Record<string, unknown>,
          timestamp: Date.now(),
        };
        this.wsClient!.send(JSON.stringify(msg));
        return; // WS delivered — skip HTTP queue
      } catch {
        // WS send failed — fall through to HTTP queue
      }
    }

    // HTTP polling fallback
    this.chatOutbox.push({ id: chunk.id, message: chunk.delta, timestamp: chunk.timestamp, _isChunk: true, _done: chunk.done } as typeof this.chatOutbox[number]);
  }

  /**
   * Get and drain pending chat responses for the plugin (called during HTTP polling).
   */
  drainChatResponses(): Array<{ id: string; message: string; timestamp: number; isError?: boolean; _isChunk?: boolean; _done?: boolean }> {
    const responses = [...this.chatOutbox];
    this.chatOutbox = [];
    if (responses.length > 0) {
      this.logger.debug("Chat responses drained for HTTP delivery", {
        count: responses.length,
        ids: responses.map(r => r.id),
      });
    }
    return responses;
  }

  /**
   * Send a command to the plugin.
   * Uses WebSocket if connected, otherwise queues for HTTP polling.
   * Pauses heartbeat while command is in-flight — the plugin is single-threaded
   * and cannot respond to pings during figma.* execution.
   */
  sendCommand(command: Command): Promise<CommandResult> {
    // Pause heartbeat — plugin can't respond to pings while executing
    this.heartbeat.pauseWsHeartbeat();

    const promise = this.queue.enqueue(command);

    // Resume heartbeat when command completes (success or failure)
    promise.then(
      () => this.heartbeat.resumeWsHeartbeat(),
      () => this.heartbeat.resumeWsHeartbeat(),
    );

    // If WebSocket is active, push immediately
    if (this.connection.isWebSocketActive && this.wsClient?.readyState === WebSocket.OPEN) {
      this.pushCommandViaWs(command);
    }

    return promise;
  }

  // ─── Route Registration ────────────────────────────────────────────────

  private registerRoutes(app: FastifyInstance): void {
    // Health endpoint — no auth required
    app.get("/health", async (_req: FastifyRequest, _reply: FastifyReply) => {
      return this.handleHealth();
    });

    // Auth middleware for plugin endpoints
    const authHook = async (req: FastifyRequest, reply: FastifyReply) => {
      try {
        const token = req.headers["x-auth-token"] as string | undefined;
        this.connection.validateAuth(token);
      } catch (err) {
        if (err instanceof RexError) {
          reply.code(401).send(err.toResponse());
        } else {
          reply.code(401).send({ error: { message: "Unauthorized" } });
        }
        // Halt request processing by returning the reply
        return reply;
      }
    };

    // POST /connect — plugin handshake (no auth required — returns the auth token)
    app.post("/connect", async (req: FastifyRequest, reply: FastifyReply) => {
      return this.handleConnect(req, reply);
    });

    // GET /commands — plugin polls for pending commands
    app.get("/commands", {
      preHandler: authHook,
    }, async (req: FastifyRequest, reply: FastifyReply) => {
      return this.handleGetCommands(req, reply);
    });

    // POST /results — plugin posts command results
    app.post("/results", {
      preHandler: authHook,
    }, async (req: FastifyRequest, reply: FastifyReply) => {
      return this.handlePostResults(req, reply);
    });

    // POST /disconnect — clean plugin disconnect
    app.post("/disconnect", {
      preHandler: authHook,
    }, async (req: FastifyRequest, reply: FastifyReply) => {
      return this.handleDisconnect(req, reply);
    });

    // POST /chat/send — plugin sends a chat message
    app.post("/chat/send", {
      preHandler: authHook,
    }, async (req: FastifyRequest, _reply: FastifyReply) => {
      const body = req.body as { id: string; message: string; selection?: unknown[] };
      if (!body?.message) {
        return { error: "Missing message field" };
      }
      const chatMsg = {
        id: body.id || `chat_${Date.now()}`,
        message: body.message,
        selection: body.selection || [],
        timestamp: Date.now(),
      };
      this.enqueueChatMessage(chatMsg);
      this.logger.info("Chat message received from plugin", { id: chatMsg.id });
      return { status: "ok", id: chatMsg.id };
    });

    // GET /chat/responses — plugin polls for chat responses
    app.get("/chat/responses", {
      preHandler: authHook,
    }, async (_req: FastifyRequest, reply: FastifyReply) => {
      const responses = this.drainChatResponses();
      if (responses.length === 0) {
        reply.code(204);
        return undefined;
      }
      return { responses };
    });

    // GET /chat/history — plugin fetches persisted chat history on connect
    app.get("/chat/history", {
      preHandler: authHook,
    }, async (_req: FastifyRequest, _reply: FastifyReply) => {
      if (!this._memoryStore || !this.connection.session) {
        return { messages: [] };
      }
      try {
        const ctx: MemoryContext = {
          fileKey: this.connection.session.fileKey,
          fileName: this.connection.session.fileName,
          userId: this.connection.session.user?.id,
          userName: this.connection.session.user?.name,
        };
        // Session-scoped history if active session exists
        const messages = this._activeChatSession
          ? await this._memoryStore.getSessionMessages(this._activeChatSession.sessionId, ctx, 50)
          : await this._memoryStore.getChatHistory(ctx, 20);
        return { messages };
      } catch (err) {
        this.logger.warn("Failed to fetch chat history", {
          error: err instanceof Error ? err.message : String(err),
        });
        return { messages: [] };
      }
    });

    // POST /session/create — create a new chat session
    app.post("/session/create", {
      preHandler: authHook,
    }, async (_req: FastifyRequest, _reply: FastifyReply) => {
      const pluginSession = this.connection.session;
      if (!this._memoryStore || !pluginSession) {
        return { error: "Not connected" };
      }
      const now = Date.now();
      const session: ChatSession = {
        sessionId: "sess_chat_" + now,
        name: "New Session",
        summary: "",
        fileKey: pluginSession.fileKey,
        createdAt: now,
        lastMessageAt: now,
        messageCount: 0,
      };
      const ctx: MemoryContext = {
        fileKey: pluginSession.fileKey,
        fileName: pluginSession.fileName,
        userId: pluginSession.user?.id,
        userName: pluginSession.user?.name,
      };
      try {
        await this._memoryStore.createSession(session, ctx);
        this._activeChatSession = session;
        this.logger.info("Chat session created", { sessionId: session.sessionId });
        return { session };
      } catch (err) {
        this.logger.warn("Failed to create chat session", {
          error: err instanceof Error ? err.message : String(err),
        });
        // Still set locally even if remote fails
        this._activeChatSession = session;
        return { session };
      }
    });

    // GET /sessions — list recent chat sessions
    app.get("/sessions", {
      preHandler: authHook,
    }, async (_req: FastifyRequest, _reply: FastifyReply) => {
      const pluginSession = this.connection.session;
      if (!this._memoryStore || !pluginSession) {
        return { sessions: [] };
      }
      try {
        const ctx: MemoryContext = {
          fileKey: pluginSession.fileKey,
          fileName: pluginSession.fileName,
          userId: pluginSession.user?.id,
          userName: pluginSession.user?.name,
        };
        const sessions = await this._memoryStore.listSessions(ctx, 20);
        return { sessions };
      } catch (err) {
        this.logger.warn("Failed to list sessions", {
          error: err instanceof Error ? err.message : String(err),
        });
        return { sessions: [] };
      }
    });

    // POST /session/select — select an existing session and load its messages
    app.post("/session/select", {
      preHandler: authHook,
    }, async (req: FastifyRequest, _reply: FastifyReply) => {
      const body = req.body as { sessionId?: string } | null;
      const pluginSession = this.connection.session;
      if (!body?.sessionId || !this._memoryStore || !pluginSession) {
        return { error: "Missing sessionId or not connected" };
      }
      const ctx: MemoryContext = {
        fileKey: pluginSession.fileKey,
        fileName: pluginSession.fileName,
        userId: pluginSession.user?.id,
        userName: pluginSession.user?.name,
      };
      try {
        const messages = await this._memoryStore.getSessionMessages(body.sessionId, ctx, 50);
        // Find the session metadata from the sessions list
        const sessions = await this._memoryStore.listSessions(ctx, 50);
        const session = sessions.find(s => s.sessionId === body.sessionId);
        if (session) {
          this._activeChatSession = session;
        } else {
          // Fallback: create a minimal session object
          this._activeChatSession = {
            sessionId: body.sessionId,
            name: "Session",
            summary: "",
            fileKey: pluginSession.fileKey,
            createdAt: Date.now(),
            lastMessageAt: Date.now(),
            messageCount: messages.length,
          };
        }
        this.logger.info("Chat session selected", { sessionId: body.sessionId, messageCount: messages.length });
        return { messages, sessionName: this._activeChatSession.name };
      } catch (err) {
        this.logger.warn("Failed to select session", {
          error: err instanceof Error ? err.message : String(err),
        });
        return { messages: [], sessionName: "Session" };
      }
    });

    // POST /session/resume — restore active session after server restart
    app.post("/session/resume", {
      preHandler: authHook,
    }, async (req: FastifyRequest, _reply: FastifyReply) => {
      const body = req.body as { sessionId?: string } | null;
      const pluginSession = this.connection.session;
      if (!body?.sessionId || !pluginSession) {
        return { status: "no-op" };
      }
      // Already have an active session — no need to resume
      if (this._activeChatSession) {
        return { status: "already-active", sessionId: this._activeChatSession.sessionId };
      }
      const ctx: MemoryContext = {
        fileKey: pluginSession.fileKey,
        fileName: pluginSession.fileName,
        userId: pluginSession.user?.id,
        userName: pluginSession.user?.name,
      };
      // Try to find the session in memory service
      if (this._memoryStore) {
        try {
          const sessions = await this._memoryStore.listSessions(ctx, 50);
          const found = sessions.find(s => s.sessionId === body.sessionId);
          if (found) {
            this._activeChatSession = found;
            this.logger.info("Chat session resumed", { sessionId: found.sessionId, name: found.name });
            return { status: "resumed", sessionId: found.sessionId, name: found.name };
          }
        } catch {
          // Fall through to minimal session
        }
      }
      // Fallback: create minimal session object
      this._activeChatSession = {
        sessionId: body.sessionId,
        name: "Resumed Session",
        summary: "",
        fileKey: pluginSession.fileKey,
        createdAt: Date.now(),
        lastMessageAt: Date.now(),
        messageCount: 0,
      };
      this.logger.info("Chat session resumed (minimal)", { sessionId: body.sessionId });
      return { status: "resumed", sessionId: body.sessionId };
    });

    // POST /session/delete — delete a session and its messages
    app.post("/session/delete", {
      preHandler: authHook,
    }, async (req: FastifyRequest, _reply: FastifyReply) => {
      const body = req.body as { sessionId?: string } | null;
      const pluginSession = this.connection.session;
      if (!body?.sessionId || !this._memoryStore || !pluginSession) {
        return { error: "Missing sessionId or not connected" };
      }
      const ctx: MemoryContext = {
        fileKey: pluginSession.fileKey,
        fileName: pluginSession.fileName,
        userId: pluginSession.user?.id,
        userName: pluginSession.user?.name,
      };
      try {
        // Delete session metadata and messages by sessionId query
        const deleted = await this._memoryStore.forget(ctx, undefined, body.sessionId, "file");
        // Clear active session if it was the deleted one
        if (this._activeChatSession?.sessionId === body.sessionId) {
          this._activeChatSession = null;
        }
        this.logger.info("Chat session deleted", { sessionId: body.sessionId, deleted });
        return { status: "deleted", sessionId: body.sessionId, deleted };
      } catch (err) {
        this.logger.warn("Failed to delete session", {
          error: err instanceof Error ? err.message : String(err),
        });
        return { error: "Failed to delete session" };
      }
    });
  }

  // ─── Route Handlers ────────────────────────────────────────────────────

  private handleHealth(): Record<string, unknown> {
    const queueStats = this.queue.getStats();
    const healthSummary = this.heartbeat.getHealthSummary();

    return {
      status: "ok",
      version: VERSION,
      uptime: Math.floor((Date.now() - this.startTime) / 1000),
      connection: this.connection.getConnectionInfo(),
      queue: {
        ...healthSummary,
        pending: queueStats.pending,
        inFlight: queueStats.inFlight,
      },
    };
  }

  private handleConnect(
    req: FastifyRequest,
    reply: FastifyReply,
  ): Record<string, unknown> {
    const body = req.body as ConnectPayload;

    if (!body?.pluginId || !body?.fileKey || !body?.fileName) {
      reply.code(400);
      return {
        error: {
          category: ErrorCategory.INVALID_PARAMS,
          message: "Missing required fields: pluginId, fileKey, fileName",
          retryable: false,
        },
      };
    }

    const session = this.connection.connect(body);

    // Start comment watcher for @rex mentions
    this.commentWatcher.start(body.fileKey);

    // Start poll monitoring
    this.heartbeat.startPollMonitoring(
      this.config.polling.defaultInterval,
      () => {
        this.logger.warn("Plugin disconnected due to missed polls");
        this.connection.disconnect("missed polls");
        this.heartbeat.stopWsHeartbeat();
      },
    );

    return {
      sessionId: session.sessionId,
      authSecret: this.connection.secret,
      config: {
        pollingInterval: this.config.polling.defaultInterval,
        burstInterval: this.config.polling.burstInterval,
        idleInterval: this.config.polling.idleInterval,
        idleThreshold: this.config.polling.idleThreshold,
        preloadFonts: this.config.figma.preloadFonts,
      },
    };
  }

  private handleGetCommands(
    req: FastifyRequest,
    reply: FastifyReply,
  ): Record<string, unknown> | undefined {
    const pluginId = req.headers["x-plugin-id"] as string | undefined;

    try {
      this.connection.validatePluginId(pluginId);
    } catch (err) {
      if (err instanceof RexError) {
        reply.code(err.category === ErrorCategory.PLUGIN_NOT_RUNNING ? 503 : 400);
        return err.toResponse() as unknown as Record<string, unknown>;
      }
      throw err;
    }

    // Update pageId from poll header (user may switch pages mid-session)
    const pageIdHeader = req.headers["x-plugin-page"] as string | undefined;
    if (pageIdHeader && this.connection.session) {
      this.connection.session.pageId = pageIdHeader;
    }

    // Record the poll
    this.heartbeat.recordPoll();

    // Keep-alive polls only record liveness — don't drain queues or return data
    const url = new URL(req.url, "http://localhost");
    if (url.searchParams.get("keepalive") === "1") {
      reply.code(204);
      return undefined;
    }

    // Get pending commands
    const pending = this.queue.getPending();

    if (pending.length === 0) {
      // Include any pending chat responses
      const chatResponses = this.drainChatResponses();

      // Even with no commands, signal activity state so the plugin
      // can show forging animation when Claude is working
      if (this.isActive || chatResponses.length > 0 || this.pendingChatCount > 0) {
        return { commands: [], activity: this.isActive, chatResponses, pendingChat: this.pendingChatCount, sessionName: this._activeChatSession?.name ?? null };
      }
      reply.code(204);
      return undefined;
    }

    // Mark commands as SENT and build the response
    const commands: Command[] = [];
    for (const entry of pending) {
      this.queue.markSent(entry.command.id);
      // For HTTP polling, mark as acknowledged implicitly (plugin received it)
      this.queue.markAcknowledged(entry.command.id);
      commands.push(entry.command);
    }

    // Track last command time for adaptive polling
    this.pollingState.lastCommandTime = Date.now();

    // Calculate suggested polling interval
    const suggestedInterval = this.calculatePollingInterval();

    // Include any pending chat responses
    const chatResponses = this.drainChatResponses();

    // Include remaining queue depth so the plugin can show progress
    const remainingStats = this.queue.getStats();

    return {
      commands,
      pollingInterval: suggestedInterval,
      activity: this.isActive,
      chatResponses,
      pendingChat: this.pendingChatCount,
      sessionName: this._activeChatSession?.name ?? null,
      queueDepth: remainingStats.pending + remainingStats.inFlight,
    };
  }

  private handlePostResults(
    req: FastifyRequest,
    reply: FastifyReply,
  ): Record<string, unknown> {
    const body = req.body as CommandResult | CommandResult[];

    // Support both single result and array of results
    const results = Array.isArray(body) ? body : [body];

    for (const result of results) {
      if (!result?.id) {
        reply.code(400);
        return {
          error: {
            category: ErrorCategory.INVALID_PARAMS,
            message: "Missing required field: id",
            retryable: false,
          },
        };
      }

      this.queue.complete(result.id, result);
    }

    return { status: "ok", processed: results.length };
  }

  private handleDisconnect(
    req: FastifyRequest,
    _reply: FastifyReply,
  ): Record<string, unknown> {
    const body = req.body as { sessionId?: string; reason?: string } | null;

    this.connection.disconnect(body?.reason ?? "plugin disconnect");
    this.heartbeat.stopWsHeartbeat();
    this.heartbeat.destroy();

    // Close WebSocket if active
    if (this.wsClient) {
      this.wsClient.close(1000, "Plugin disconnected");
      this.wsClient = null;
    }

    return { status: "ok" };
  }

  // ─── WebSocket Handling ────────────────────────────────────────────────

  private handleUpgrade(
    request: IncomingMessage,
    socket: Duplex,
    head: Buffer,
  ): void {
    // Only handle /ws path
    const url = new URL(request.url ?? "/", "http://localhost");
    if (url.pathname !== "/ws") {
      socket.destroy();
      return;
    }

    // Validate auth token (headers or query params — browser WS API can't set headers)
    const token = (request.headers["x-auth-token"] as string | undefined)
      ?? url.searchParams.get("token")
      ?? undefined;
    try {
      this.connection.validateAuth(token);
    } catch {
      socket.write("HTTP/1.1 401 Unauthorized\r\n\r\n");
      socket.destroy();
      return;
    }

    // Validate session (headers or query params)
    const sessionId = (request.headers["x-session-id"] as string | undefined)
      ?? url.searchParams.get("sessionId")
      ?? undefined;
    if (!sessionId || !this.connection.session || this.connection.session.sessionId !== sessionId) {
      socket.write("HTTP/1.1 400 Bad Request\r\n\r\n");
      socket.destroy();
      return;
    }

    // Perform the upgrade
    this.wss!.handleUpgrade(request, socket, head, (ws) => {
      this.onWebSocketConnection(ws);
    });
  }

  private onWebSocketConnection(ws: WebSocket): void {
    // Close any existing WS client
    if (this.wsClient) {
      this.wsClient.close(1000, "Replaced by new connection");
    }

    this.wsClient = ws;
    const sessionId = this.connection.session?.sessionId ?? "unknown";
    this.connection.upgradeToWebSocket(sessionId);

    this.logger.info("WebSocket client connected", { sessionId });

    // Start heartbeat
    this.heartbeat.startWsHeartbeat(
      () => this.wsSendPing(),
      () => {
        this.logger.warn("WebSocket heartbeat failed, degrading to HTTP");
        this.connection.downgradeToPolling();
        this.heartbeat.recordReconnect();
        ws.close(1001, "Heartbeat timeout");
      },
    );

    // Send any pending commands immediately
    const pending = this.queue.getPending();
    for (const entry of pending) {
      this.pushCommandViaWs(entry.command);
    }

    ws.on("message", (data: Buffer) => {
      this.onWsMessage(data);
    });

    ws.on("close", (_code: number, _reason: Buffer) => {
      this.logger.info("WebSocket client disconnected");
      this.heartbeat.stopWsHeartbeat();

      if (this.wsClient === ws) {
        this.wsClient = null;
        this.connection.downgradeToPolling();
      }
    });

    ws.on("error", (err: Error) => {
      this.logger.error("WebSocket error", { error: err.message });
    });
  }

  private onWsMessage(data: Buffer): void {
    this.heartbeat.recordWsMessage();

    let msg: WsMessage;
    try {
      msg = JSON.parse(data.toString()) as WsMessage;
    } catch {
      this.logger.warn("Invalid WebSocket message (not JSON)");
      return;
    }

    switch (msg.type) {
      case "pong":
        this.heartbeat.recordPong();
        break;

      case "ack":
        if (msg.id) {
          this.queue.markAcknowledged(msg.id);
        }
        break;

      case "result":
        if (msg.id && msg.payload) {
          const result = msg.payload as unknown as CommandResult;
          // Ensure the result has the command ID
          result.id = result.id ?? msg.id;
          this.queue.complete(result.id, result);
        }
        break;

      default:
        this.logger.warn("Unknown WebSocket message type", { type: msg.type });
    }
  }

  /** Send a command to the plugin via WebSocket. */
  private pushCommandViaWs(command: Command): void {
    if (!this.wsClient || this.wsClient.readyState !== WebSocket.OPEN) return;

    // Include queue depth so the plugin can show progress
    const stats = this.queue.getStats();
    const payload = {
      ...(command as unknown as Record<string, unknown>),
      _queueDepth: stats.pending + stats.inFlight,
    };

    const msg: WsMessage = {
      type: "command",
      id: command.id,
      payload,
      timestamp: Date.now(),
    };

    this.wsClient.send(JSON.stringify(msg));
    this.queue.markSent(command.id);

    this.logger.debug("Command pushed via WebSocket", {
      commandId: command.id,
      type: command.type,
    });
  }

  /** Send a ping message over WebSocket. */
  private wsSendPing(): void {
    if (!this.wsClient || this.wsClient.readyState !== WebSocket.OPEN) return;

    const msg: WsMessage = {
      type: "ping",
      timestamp: Date.now(),
    };

    this.wsClient.send(JSON.stringify(msg));
  }

  // ─── Adaptive Polling ──────────────────────────────────────────────────

  /** Calculate the suggested polling interval based on queue activity. */
  private calculatePollingInterval(): number {
    const { burstInterval, defaultInterval, idleInterval, idleThreshold } = this.config.polling;
    const queueStats = this.queue.getStats();

    // Burst mode: commands are pending
    if (queueStats.pending > 0 || queueStats.inFlight > 0) {
      return burstInterval;
    }

    // Idle mode: no commands for a while
    const timeSinceLastCommand = Date.now() - this.pollingState.lastCommandTime;
    if (timeSinceLastCommand > idleThreshold) {
      return idleInterval;
    }

    // Default
    return defaultInterval;
  }
}
